"use client";

import { useState } from "react";
import { useNavigate } from "react-router-dom";

export default function AddNewProduct() {
    const [inStock, setInStock] = useState(false);
    const [quantity, setQuantity] = useState("");
    const [images, setImages] = useState([]); // ✅ state สำหรับเก็บรูป
    const navigate = useNavigate();

    return (
        <div className="min-h-screen bg-gray-50 font-sans">
            {/* Header */}
            <header className="bg-white shadow">
                <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
                    <div className="flex items-center gap-2">
                        <img
                            src="/images/WholeCart_logo.png"
                            alt="WholeCart"
                            className="h-12 w-auto"
                        />
                        <span className="ml-4 text-gray-600">Admin username</span>
                    </div>
                    <button className="text-gray-800 font-medium">Log out</button>
                </div>
            </header>

            {/* Main */}
            <main className="max-w-7xl mx-auto p-6">
                <h1 className="text-xl font-bold text-green-600 mb-4">Add New Product</h1>

                {/* Breadcrumb + Back Button */}
                <div className="flex justify-between items-center mb-6">
                    <p className="text-sm text-gray-500">
                        Dashboard / Add Products
                    </p>
                    <button
                        className="bg-gray-500 text-white px-4 py-1 rounded"
                        onClick={() => navigate("/admin-dashboard")}
                    >
                        Back to Product
                    </button>
                </div>

                <div className="flex gap-6">
                    {/* Left Section */}
                    <div className="flex-1 bg-white border rounded p-6">
                        <h2 className="text-md font-semibold text-gray-700 mb-4">
                            Product Information
                        </h2>

                        {/* Title */}
                        <label className="block text-sm text-gray-600 mb-1">Title</label>
                        <input
                            type="text"
                            placeholder="Product Name"
                            className="w-full border rounded px-3 py-2 mb-4"
                        />

                        {/* Status Stock Toggle */}
                        <div className="flex items-center gap-3 mb-4">
                            <span className="text-sm text-gray-600">Status Stock</span>
                            <button
                                onClick={() => setInStock(!inStock)}
                                className={`w-12 h-6 flex items-center rounded-full p-1 transition ${
                                    inStock ? "bg-green-500" : "bg-red-500"
                                }`}
                            >
                                <div
                                    className={`bg-white w-4 h-4 rounded-full shadow-md transform transition ${
                                        inStock ? "translate-x-6" : ""
                                    }`}
                                />
                            </button>
                            <span
                                className={`text-sm font-medium ${
                                    inStock ? "text-green-600" : "text-red-600"
                                }`}
                            >
                                {inStock ? "In stock" : "Out of stock"}
                            </span>
                        </div>

                        {/* Quantity Input (show only if in stock) */}
                        {inStock && (
                            <div className="mb-4">
                                <label className="block text-sm text-gray-600 mb-1">
                                    Quantity
                                </label>
                                <input
                                    type="number"
                                    value={quantity}
                                    onChange={(e) => setQuantity(e.target.value)}
                                    placeholder="Enter quantity"
                                    className="w-full border rounded px-3 py-2"
                                />
                            </div>
                        )}

                        {/* Product Images */}
                        <div className="mb-4">
                            <label className="block text-sm text-gray-600 mb-1">
                                Product Images
                            </label>

                            {/* input สำหรับเลือกหลายไฟล์ */}
                            <input
                                type="file"
                                multiple
                                accept="image/*"
                                onChange={(e) => {
                                    const files = Array.from(e.target.files);
                                    const newImages = files.map((file) => ({
                                        file,
                                        url: URL.createObjectURL(file),
                                    }));
                                    setImages((prev) => [...prev, ...newImages]);
                                }}
                                className="mb-2"
                            />

                            {/* กล่อง Drop zone (โครงสร้างเดิม) */}
                            <div className="border-dashed border-2 border-gray-300 rounded h-32 flex items-center justify-center text-gray-400">
                                Drop files here
                            </div>

                            {/* แสดงรูปที่อัปโหลด */}
                            <div className="flex flex-wrap gap-4 mt-4">
                                {images.map((img, index) => (
                                    <div
                                        key={index}
                                        className="relative w-32 h-32 rounded-lg overflow-hidden border shadow"
                                    >
                                        <img
                                            src={img.url}
                                            alt="product"
                                            className="w-full h-full object-cover"
                                        />
                                        <button
                                            onClick={() =>
                                                setImages((prev) =>
                                                    prev.filter((_, i) => i !== index)
                                                )
                                            }
                                            className="absolute top-1 right-1 bg-red-600 text-white rounded-full w-6 h-6 flex items-center justify-center text-xs"
                                        >
                                            ✕
                                        </button>
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Description */}
                        <label className="block text-sm text-gray-600 mb-1">
                            Product Description
                        </label>
                        <textarea
                            className="w-full border rounded px-3 py-2"
                            rows="3"
                        ></textarea>
                    </div>

                    {/* Right Section */}
                    <div className="w-80">
                        <div className="bg-white border rounded p-6">
                            <h2 className="text-md font-semibold text-gray-700 mb-4">
                                Product Price
                            </h2>
                            <label className="block text-sm text-gray-600 mb-1">
                                Sale Price
                            </label>
                            <input
                                type="number"
                                placeholder="$0.00"
                                className="w-full border rounded px-3 py-2 mb-4"
                            />
                            <button className="bg-green-600 text-white w-full py-2 rounded hover:bg-green-700">
                                Create Product
                            </button>
                        </div>
                    </div>
                </div>
            </main>
        </div>
    );
}
